// ════════════════════════════════════════════════
// CONFIGURAR UMA VEZ POR INSTÂNCIA N8N
// ════════════════════════════════════════════════

const DASHBOARD_URL  = "https://fabricante-dashboard-production.up.railway.app";
const WEBHOOK_SECRET = "pprrc1357";
const TENANT_SLUG    = "igui";

// ════════════════════════════════════════════════
// LÓGICA (não alterar)
// ════════════════════════════════════════════════
const webhookData     = $input.first().json;
const body            = webhookData.body   ?? webhookData;
const params          = webhookData.params ?? {};

if (body.eventType !== 'CONTACT_TAG_UPDATE') {
  return [{ json: { skip: true } }];
}

const contactId       = body.content?.id;
const tagsId          = body.content?.tagsId ?? [];
const occurredAt      = body.date ?? new Date().toISOString();
const storeExternalId = params.storeExternalId;

if (!contactId || !storeExternalId) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    skip:             false,
    contactId,
    tagsId,
    occurredAt,
    storeExternalId,
    dashboardUrl:     DASHBOARD_URL,
    webhookSecret:    WEBHOOK_SECRET,
    tenantSlug:       TENANT_SLUG,
  }
}];

const init       = $('Configurar Instância').first().json;
const configResp = $input.first().json;

if (init.skip) return [{ json: { skip: true } }];

// Config não encontrada no backend
if (configResp.error || !Array.isArray(configResp.stageMap)) {
  return [{ json: { skip: true } }];
}

const { contactId, tagsId, occurredAt, storeExternalId, dashboardUrl, webhookSecret, tenantSlug } = init;

const stageMap      = configResp.stageMap;
const stagePriority = Array.isArray(configResp.stagePriority) ? configResp.stagePriority : [];

// Constrói lookup tagId → {stepId, dashKey}
const stageByTagId = {};
for (const entry of stageMap) {
  if (entry.tagId) stageByTagId[entry.tagId] = entry;
}

const matched = tagsId.filter(t => stageByTagId[t]);
if (matched.length === 0) return [{ json: { skip: true } }];

const winner = stagePriority.find(s => matched.includes(s)) ?? matched[0];
const stage  = stageByTagId[winner];

return [{
  json: {
    skip:             false,
    contactId,
    stepId:           stage.stepId  ?? null,
    dashKey:          stage.dashKey ?? null,
    sendToDash:       (stage.dashKey ?? null) !== null,
    storeExternalId,
    dashboardUrl,
    webhookSecret,
    tenantSlug,
    occurredAt,
    eventId:          contactId + '-' + occurredAt,
  }
}];

const ctx  = $('Determinar Etapa').first().json;
const data = $('Buscar Dados Helena').first().json;

if (!ctx.sendToDash) return [];

const meta = {};
if (data.agentEmail)             meta.crmUserId       = data.agentEmail;
if (data.agentName)              meta.salespersonName = data.agentName;
if (data.contactName)            meta.name            = data.contactName;
if (data.contactPhone)           meta.phone           = data.contactPhone;
if (data.monetaryAmount != null) { meta.value = data.monetaryAmount; meta.currency = 'BRL'; }
if (data.utmSource)              meta.utm_source      = data.utmSource;
if (data.utmMedium)              meta.utm_medium      = data.utmMedium;
if (data.utmCampaign)            meta.utm_campaign    = data.utmCampaign;
if (data.utmContent)             meta.utm_content     = data.utmContent;

const payload = JSON.stringify({
  event_id:          ctx.eventId,
  crm_source:        'helena',
  tenant_slug:       ctx.tenantSlug,
  store_external_id: ctx.storeExternalId,
  lead_external_id:  ctx.contactId,
  to_stage:          ctx.dashKey,
  occurred_at:       ctx.occurredAt,
  metadata:          meta
});

return [{ json: { ...ctx, payload } }];
